// Sort colleges automatically by reputation (derived from lowest general cutoff rank)
collegesData.sort((a, b) => {
  const getMinRank = (c: College) => Math.min(...c.branches2024.map(branch => branch.generalCR));
  return getMinRank(a) - getMinRank(b);
});
